def factorial(n):
    # Check if n is a non-negative integer
    if not isinstance(n, int) or n < 0:
        raise ValueError("Input must be a non-negative integer")

    # Base case: factorial of 0 is 1
    if n == 0:
        return 1
    else:
        result = 1

        for i in range(1, n + 1):
            result *= i

        return result
```

```python
def clamp(x, lo, hi):
    if x < lo:
        return lo
    elif x > hi:
        return hi
    else:
        return x
```

```python
def unique(lst):
    return sorted(set(lst), key=lambda x: lst.index(x))
```

```python
def dot_product(a, b):
    """Compute the dot product of two lists."""
    if len(a) != len(b):
        raise ValueError("Lists must have the same length")

    result = 0
    for i in range(len(a)):
        result += a[i] * b[i]

    return result
```

```python
def char_frequency(s):
    freq_dict = {}
    for ch in s:
        if ch in freq_dict:
            freq_dict[ch] += 1
        else:
            freq_dict[ch] = 1
    return freq_dict
```

```python
def fib(n):
    if n <= 0:
        return "Input should be positive integer"
    elif n == 1:
        return 0
    elif n == 2:
        return 1
    else:
        a, b = 0, 1
        for _ in range(n-1):
            a, b = b, a + b
        return a
```

```
def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True
```

```python
def power(base, exp):
    if exp == 0:
        return 1
    elif exp < 0:
        return 1 / power(base, -exp)
    else:
        quotient = 1
        remainder = base

        for _ in range(exp - 1):
            quotient, remainder = remainder, quotient % remainder

        return remainder
```
